#include <iostream>
#include <vector>
#include <cmath>
using namespace std;

int main() {
    int n;
    cin >> n;
    
    vector<int> h(n);
    for (int i = 0; i < n; i++) {
        cin >> h[i];
    }
    
    if (n == 1) {
        cout << 0 << endl;
        return 0;
    }
    
    int prevPrev = 0;
    int prev = abs(h[1] - h[0]);
    int current;
    
    for (int i = 2; i < n; i++) {
        int fromPrev = prev + abs(h[i] - h[i-1]);
        int fromPrevPrev = prevPrev + abs(h[i] - h[i-2]);
        current = min(fromPrev, fromPrevPrev);
        prevPrev = prev;
        prev = current;
    }
    
    cout << prev << endl;
    
    return 0;
}

